import React, { useState, useEffect, useRef } from 'react';
import { PageHeader, Modal } from '../../components/UI';

// ============================================================
// API ExerciseDB — fetch depuis le NAVIGATEUR (pas de CORS)
// https://exercisedb-api.vercel.app/api/v1
// ============================================================
const API = 'https://exercisedb-api.vercel.app/api/v1';

// Noms de recherche pour chaque exercice (correspond aux noms dans l'API)
const muscles = [
  {
    id: 1, nom: 'Biceps', icon: 'bi-lightning-charge', zone: 'Bras',
    searchGroup: 'upper arms',
    exercices: [
      { nom: 'Curl barre',             series: '4×10', search: 'barbell curl',             desc: 'Debout, barre en supination. Fléchir les coudes jusqu\'à la hauteur des épaules.' },
      { nom: 'Curl haltères alternés', series: '3×12', search: 'dumbbell alternate bicep curl', desc: 'Alterner gauche-droite en contrôlant la descente. Tourner le poignet en haut.' },
      { nom: 'Curl marteau',           series: '3×12', search: 'hammer curl',               desc: 'Prise neutre (pouce vers le haut). Cible aussi le brachial et l\'avant-bras.' },
      { nom: 'Curl concentré',         series: '3×15', search: 'concentration curl',        desc: 'Assis, coude appuyé sur la cuisse. Excellent pour le pic du biceps.' },
    ]
  },
  {
    id: 2, nom: 'Triceps', icon: 'bi-lightning', zone: 'Bras',
    searchGroup: 'upper arms',
    exercices: [
      { nom: 'Dips',            series: '4×12', search: 'chest dip',                         desc: 'Corps vertical, coudes près du corps. Plus efficace avec lest quand maîtrisé.' },
      { nom: 'Extension nuque', series: '3×12', search: 'dumbbell triceps extension',         desc: 'Haltère ou barre EZ derrière la tête. Cible le chef long du triceps.' },
      { nom: 'Pushdown câble',  series: '4×15', search: 'cable rope overhead tricep extension',desc: 'Câble haute poulie, coudes fixes. Excellent pour la finition et le pump.' },
      { nom: 'Pompes diamant',  series: '3×15', search: 'diamond push up',                   desc: 'Mains en triangle sous le sternum. Variante au poids du corps très efficace.' },
    ]
  },
  {
    id: 3, nom: 'Pectoraux', icon: 'bi-person-arms-up', zone: 'Buste',
    searchGroup: 'chest',
    exercices: [
      { nom: 'Développé couché',  series: '5×8',  search: 'barbell bench press',          desc: 'Le roi des exercices de poitrine. Descendre la barre jusqu\'à effleurer le sternum.' },
      { nom: 'Développé incliné', series: '4×10', search: 'barbell incline bench press',  desc: 'Banc à 30-45°. Cible le faisceau supérieur pour un pec plus complet.' },
      { nom: 'Écarté haltères',   series: '3×12', search: 'dumbbell fly',                 desc: 'Légère flexion des coudes. Mouvement d\'isolation, descente lente et contrôlée.' },
      { nom: 'Crossover câbles',  series: '3×15', search: 'cable crossover',              desc: 'Croisement des mains en bas. Étirement maximal du grand pectoral.' },
    ]
  },
  {
    id: 4, nom: 'Dos', icon: 'bi-arrows-expand-vertical', zone: 'Dos',
    searchGroup: 'back',
    exercices: [
      { nom: 'Tractions',           series: '4×8',  search: 'pull-up',              desc: 'Prise large pronation. Le squat du dos. Ajouter du lest progressivement.' },
      { nom: 'Rowing barre',        series: '4×10', search: 'barbell bent over row', desc: 'Tronc parallèle au sol, tirer vers le nombril. Excellent pour l\'épaisseur.' },
      { nom: 'Tirage poulie haute', series: '3×12', search: 'cable lat pulldown',    desc: 'Tirer vers le haut du sternum. Alternatif aux tractions pour les débutants.' },
      { nom: 'Soulevé de terre',    series: '4×6',  search: 'barbell deadlift',      desc: 'Le mouvement roi. Dos droit, gainage total, poussée des talons dans le sol.' },
    ]
  },
  {
    id: 5, nom: 'Épaules', icon: 'bi-award', zone: 'Épaules',
    searchGroup: 'shoulders',
    exercices: [
      { nom: 'Développé militaire', series: '4×10', search: 'barbell overhead press',      desc: 'Debout ou assis, barre ou haltères. Cible le faisceau antérieur en priorité.' },
      { nom: 'Élévation latérale',  series: '4×15', search: 'dumbbell lateral raise',      desc: 'Petits poids, coudes légèrement fléchis. Faisceau latéral = épaules larges.' },
      { nom: 'Oiseau (Rear delt)',  series: '3×15', search: 'dumbbell rear lateral raise',  desc: 'Tronc penché, bras en croix. Indispensable pour équilibrer posture et force.' },
      { nom: 'Shrugs',              series: '4×12', search: 'dumbbell shrug',               desc: 'Haussement d\'épaules avec haltères ou barre. Cible les trapèzes supérieurs.' },
    ]
  },
  {
    id: 6, nom: 'Jambes', icon: 'bi-activity', zone: 'Jambes',
    searchGroup: 'upper legs',
    exercices: [
      { nom: 'Squat',           series: '5×8',  search: 'barbell squat',      desc: 'Le roi des exercices. Descendre cuisses parallèles, dos droit, genoux dans l\'axe.' },
      { nom: 'Presse à cuisses',series: '4×12', search: 'leg press',          desc: 'Pieds hauts = ischios/fessiers. Pieds bas = quadriceps. Contrôler la montée.' },
      { nom: 'Fentes marchées', series: '3×10', search: 'dumbbell lunge',     desc: 'Chaque jambe. Grand pas, genou avant à 90°. Excellent pour l\'équilibre.' },
      { nom: 'Leg extension',   series: '3×15', search: 'leg extension',      desc: 'Isolation quadriceps. Finition en fin de séance pour le pump.' },
      { nom: 'Leg curl',        series: '3×15', search: 'seated leg curl',    desc: 'Isolation ischios-jambiers. Ne pas négliger les muscles postérieurs.' },
    ]
  },
  {
    id: 7, nom: 'Abdominaux', icon: 'bi-grid-3x3', zone: 'Core',
    searchGroup: 'waist',
    exercices: [
      { nom: 'Gainage planche',  series: '4×60s', search: 'plank',                desc: 'Corps aligné, contractez abdos et fessiers. Base indispensable du gainage.' },
      { nom: 'Crunch câble',     series: '4×20',  search: 'cable crunch',         desc: 'Plus efficace que le crunch classique car résistance constante sur tout le mouvement.' },
      { nom: 'Relevé de jambes', series: '3×15',  search: 'hanging leg raise',    desc: 'Suspendu ou allongé. Cible le bas du ventre (droit inférieur).' },
      { nom: 'Russian twist',    series: '3×20',  search: 'russian twist',        desc: 'Avec médecine-ball ou haltère. Cible les obliques et la rotation du tronc.' },
    ]
  },
  {
    id: 8, nom: 'Mollets', icon: 'bi-arrow-up-circle', zone: 'Jambes',
    searchGroup: 'lower legs',
    exercices: [
      { nom: 'Extensions mollets debout', series: '5×20', search: 'standing calf raise',  desc: 'Amplitude complète, tenir 1s en haut. Les mollets récupèrent vite, volume élevé.' },
      { nom: 'Extensions assis',          series: '4×20', search: 'seated calf raise',    desc: 'Cible le soléaire (muscle profond). Indispensable pour des mollets complets.' },
    ]
  },
];

// ============================================================
// Hook — fetch le GIF d'un exercice via l'API (depuis le navigateur)
// ============================================================
function useExerciseGif(searchTerm) {
  const [gif, setGif] = useState(null);
  const [loading, setLoading] = useState(false);
  const cache = useRef({});

  useEffect(() => {
    if (!searchTerm) return;
    if (cache.current[searchTerm]) { setGif(cache.current[searchTerm]); return; }

    setLoading(true);
    setGif(null);

    const encoded = encodeURIComponent(searchTerm.toLowerCase());
    fetch(`${API}/exercises/search?name=${encoded}&limit=1`)
      .then(r => r.json())
      .then(data => {
        const item = data?.data?.[0] || data?.[0];
        const url = item?.gifUrl || item?.gif_url || null;
        cache.current[searchTerm] = url;
        setGif(url);
      })
      .catch(() => setGif(null))
      .finally(() => setLoading(false));
  }, [searchTerm]);

  return { gif, loading };
}

// ============================================================
// Hook — fetch le GIF du groupe musculaire (bodyPart)
// ============================================================
function useGroupGif(bodyPart) {
  const [gif, setGif] = useState(null);
  const cache = useRef({});

  useEffect(() => {
    if (!bodyPart) return;
    if (cache.current[bodyPart]) { setGif(cache.current[bodyPart]); return; }

    const encoded = encodeURIComponent(bodyPart);
    fetch(`${API}/exercises/bodyPart/${encoded}?limit=1`)
      .then(r => r.json())
      .then(data => {
        const item = data?.data?.[0] || data?.[0];
        const url = item?.gifUrl || item?.gif_url || null;
        cache.current[bodyPart] = url;
        setGif(url);
      })
      .catch(() => setGif(null));
  }, [bodyPart]);

  return gif;
}

// ============================================================
// Composants visuels
// ============================================================
function GifDisplay({ gif, loading, icon, label, style = {} }) {
  if (loading) return (
    <div style={{ width:'100%', height:'100%', display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', gap:10, ...style }}>
      <div style={{ width:28, height:28, border:'2px solid var(--red)', borderTopColor:'transparent', borderRadius:'50%', animation:'spin 0.8s linear infinite' }} />
      <span style={{ fontSize:11, color:'var(--text-dim)' }}>Chargement...</span>
    </div>
  );
  if (gif) return <img src={gif} alt={label} style={{ width:'100%', height:'100%', objectFit:'cover', display:'block', ...style }} />;
  return (
    <div style={{ width:'100%', height:'100%', display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', gap:8, ...style }}>
      <i className={`bi ${icon}`} style={{ fontSize:32, color:'var(--red)', opacity:.5 }} />
      <span style={{ fontSize:11, color:'var(--text-dim)' }}>{label}</span>
    </div>
  );
}

// Card muscle avec fetch auto
function MuscleCard({ muscle, onClick }) {
  const gif = useGroupGif(muscle.searchGroup);
  return (
    <div className="fz-card hoverable" style={{ overflow:'hidden', padding:0 }} onClick={onClick}>
      <div className="muscle-img-placeholder" style={{ position:'relative', overflow:'hidden', background:'#111' }}>
        <GifDisplay gif={gif} loading={!gif && true} icon={muscle.icon} label={muscle.nom} style={{ objectFit:'cover' }} />
      </div>
      <div style={{ padding:'12px 14px' }}>
        <div style={{ fontFamily:'var(--font-heading)', fontSize:16, fontWeight:700, marginBottom:2 }}>{muscle.nom}</div>
        <div style={{ fontSize:10, color:'var(--text-dim)', marginBottom:8 }}>{muscle.zone} · {muscle.exercices.length} exercices</div>
        {muscle.exercices.slice(0,2).map(e => (
          <div key={e.nom} style={{ fontSize:11, color:'var(--text-muted)', marginBottom:2 }}>
            <i className="bi bi-chevron-right me-1" style={{ fontSize:9, color:'var(--red)' }}></i>{e.nom}
          </div>
        ))}
        <div style={{ fontSize:10, color:'var(--text-dim)', marginTop:4 }}>+{muscle.exercices.length-2} autres...</div>
      </div>
    </div>
  );
}

// Exercice row cliquable avec son GIF
function ExerciceRow({ exo, isActive, onClick }) {
  const { gif, loading } = useExerciseGif(isActive || exo._preload ? exo.search : null);
  // Stocker le gif dans l'objet pour le passer au parent
  useEffect(() => { if (gif) exo._gif = gif; }, [gif]);

  return (
    <div
      onClick={onClick}
      style={{
        background: isActive ? 'rgba(220,38,38,0.08)' : 'var(--surface2)',
        borderRadius:10, padding:'14px 16px',
        borderLeft:'3px solid var(--red)',
        cursor:'pointer', transition:'all 0.15s ease',
        outline: isActive ? '1px solid rgba(220,38,38,0.3)' : '1px solid transparent',
      }}
    >
      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:6 }}>
        <div style={{ display:'flex', alignItems:'center', gap:10 }}>
          <div style={{
            width:26, height:26, borderRadius:'50%',
            background: isActive ? 'var(--red)' : 'rgba(255,255,255,0.06)',
            border: isActive ? 'none' : '1px solid rgba(255,255,255,0.1)',
            display:'flex', alignItems:'center', justifyContent:'center',
            flexShrink:0, transition:'all 0.15s',
            position:'relative'
          }}>
            {loading && isActive
              ? <div style={{ width:10, height:10, border:'1.5px solid #fff', borderTopColor:'transparent', borderRadius:'50%', animation:'spin 0.8s linear infinite' }} />
              : <i className={`bi bi-${isActive ? 'pause-fill' : 'play-fill'}`} style={{ fontSize:10, color: isActive ? '#fff' : 'var(--red)', marginLeft: isActive ? 0 : 1 }} />
            }
          </div>
          <div style={{ fontFamily:'var(--font-heading)', fontSize:15, fontWeight:700, color: isActive ? '#fff' : 'inherit' }}>
            {exo.nom}
          </div>
        </div>
        <span className="fz-badge type">{exo.series}</span>
      </div>
      <p style={{ fontSize:12, color:'var(--text-muted)', margin:0, lineHeight:1.6, paddingLeft:36 }}>
        {exo.desc}
      </p>
    </div>
  );
}

// ============================================================
// Composant principal
// ============================================================
export default function Musculation() {
  const [selected, setSelected] = useState(null);
  const [activeExo, setActiveExo] = useState(null);
  const [displayGif, setDisplayGif] = useState(null);
  const groupGif = useGroupGif(selected?.searchGroup);
  const { gif: exoGif, loading: exoLoading } = useExerciseGif(activeExo?.search);

  const openMuscle = (m) => { setSelected(m); setActiveExo(null); setDisplayGif(null); };

  // Met à jour le GIF affiché en haut selon l'exercice actif
  useEffect(() => {
    if (activeExo) setDisplayGif(exoGif);
    else setDisplayGif(groupGif);
  }, [activeExo, exoGif, groupGif]);

  return (
    <div>
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
      <PageHeader eyebrow="Guide d'entraînement" title="Exercices par" accent="Groupe Musculaire" />

      <div style={{ padding:'16px 28px 8px', fontSize:13, color:'var(--text-muted)' }}>
        Cliquez sur un groupe musculaire pour voir les exercices. Les GIFs se chargent automatiquement.
      </div>

      {/* Grille muscles */}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:14, padding:'12px 28px 32px' }}>
        {muscles.map(m => (
          <MuscleCard key={m.id} muscle={m} onClick={() => openMuscle(m)} />
        ))}
      </div>

      {/* Modale */}
      <Modal show={!!selected} title={selected?.nom} onClose={() => setSelected(null)} size="lg">
        {selected && (
          <div>
            {/* Badges */}
            <div style={{ display:'flex', gap:12, marginBottom:16, flexWrap:'wrap', alignItems:'center' }}>
              <span className="fz-badge type">{selected.zone}</span>
              <span style={{ fontSize:12, color:'var(--text-muted)' }}>{selected.exercices.length} exercices</span>
              {activeExo && (
                <span onClick={() => setActiveExo(null)} style={{ fontSize:11, color:'var(--red)', marginLeft:'auto', cursor:'pointer', display:'flex', alignItems:'center', gap:4 }}>
                  <i className="bi bi-arrow-left" style={{ fontSize:10 }}></i> Groupe musculaire
                </span>
              )}
            </div>

            {/* Vidéo/GIF principale */}
            <div style={{ marginBottom:20, borderRadius:10, border:'1px solid var(--border)', height:250, overflow:'hidden', background:'#0d0d0d', position:'relative', display:'flex', alignItems:'center', justifyContent:'center' }}>
              {activeExo && exoLoading
                ? <GifDisplay gif={null} loading={true} icon={selected.icon} label="" />
                : <GifDisplay gif={displayGif} loading={false} icon={selected.icon} label={`[ GIF ${selected.nom} ]`} style={{ objectFit:'contain' }} />
              }
              {activeExo && displayGif && (
                <div style={{
                  position:'absolute', bottom:0, left:0, right:0,
                  background:'linear-gradient(transparent, rgba(0,0,0,0.85))',
                  padding:'30px 16px 12px',
                  fontFamily:'var(--font-heading)', fontSize:14, fontWeight:700, color:'#fff',
                  display:'flex', alignItems:'center', gap:8
                }}>
                  <i className="bi bi-play-circle-fill" style={{ color:'var(--red)', fontSize:16 }}></i>
                  {activeExo.nom}
                </div>
              )}
            </div>

            {/* Liste exercices */}
            <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
              {selected.exercices.map((e) => (
                <ExerciceRow
                  key={e.nom}
                  exo={e}
                  isActive={activeExo?.nom === e.nom}
                  onClick={() => setActiveExo(activeExo?.nom === e.nom ? null : e)}
                />
              ))}
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
}
